1	import { useAuth } from '@rhino-dev/rhino-react';
     2	import { Routes, Route, Navigate } from 'react-router-dom';
     3	
     4	import { LoginPage } from './pages/LoginPage';
     5	import { AppShell } from './components/AppShell';
     6	import { ProjectsPage } from './pages/ProjectsPage';
     7	import { ProjectDetailPage } from './pages/ProjectDetailPage';
     8	import { TasksPage } from './pages/TasksPage';
     9	import { LabelsPage } from './pages/LabelsPage';
    10	import { TrashPage } from './pages/TrashPage';
    11	import { MembersPage } from './pages/MembersPage';
    12	import { DashboardPage } from './pages/DashboardPage';
    13	import { BlogsPage } from './pages/BlogsPage';
    14	import { BlogDetailPage } from './pages/BlogDetailPage';
    15	
    16	export function App() {
    17	  const { isAuthenticated } = useAuth();
    18	
    19	  if (!isAuthenticated) {
    20	    return (
    21	      <Routes>
    22	        <Route path="*" element={<LoginPage />} />
    23	      </Routes>
    24	    );
    25	  }
    26	
    27	  return (
    28	    <AppShell>
    29	      <Routes>
    30	        <Route path="/" element={<Navigate to="/dashboard" replace />} />
    31	        <Route path="/dashboard" element={<DashboardPage />} />
    32	        <Route path="/projects" element={<ProjectsPage />} />
    33	        <Route path="/projects/:id" element={<ProjectDetailPage />} />
    34	        <Route path="/blogs" element={<BlogsPage />} />
    35	        <Route path="/blogs/:id" element={<BlogDetailPage />} />
    36	        <Route path="/tasks" element={<TasksPage />} />
    37	        <Route path="/labels" element={<LabelsPage />} />
    38	        <Route path="/trash" element={<TrashPage />} />
    39	        <Route path="/members" element={<MembersPage />} />
    40	        <Route path="*" element={<Navigate to="/dashboard" replace />} />
    41	      </Routes>
    42	    </AppShell>
    43	  );
    44	}
